## Overview

Create the server-side admin route file `apps/server/src/routes/admin.ts` with two endpoints: `POST /api/admin/reset` and `POST /api/admin/restart`. Also refactor the existing `shutdown()` function in `index.ts` to extract a reusable `shutdownServices()`, mount the admin router, and add `express-rate-limit` as a dependency.

## Step 1: Add express-rate-limit dependency

Run:
```bash
pnpm --filter=@dorkos/server add express-rate-limit
```

## Step 2: Refactor shutdown() in apps/server/src/index.ts

Extract the body of the existing `shutdown()` function (around lines 284-312) into a standalone `shutdownServices()` async function that performs the ordered teardown WITHOUT calling `process.exit()`. The existing `shutdown()` signal handler should call `shutdownServices()` then `process.exit(0)`.

Before (current code):
```typescript
async function shutdown() {
  logger.info('Shutting down...');
  if (healthCheckInterval) clearInterval(healthCheckInterval);
  if (sessionBroadcaster) sessionBroadcaster.shutdown();
  if (schedulerService) await schedulerService.stop();
  if (adapterManager) await adapterManager.shutdown();
  if (relayCore) await relayCore.close();
  if (traceStore) traceStore.close();
  if (meshCore) {
    meshCore.stopPeriodicReconciliation();
    meshCore.close();
  }
  await tunnelManager.stop();
  process.exit(0);
}
```

After:
```typescript
async function shutdownServices() {
  logger.info('Shutting down services...');
  if (healthCheckInterval) clearInterval(healthCheckInterval);
  if (sessionBroadcaster) sessionBroadcaster.shutdown();
  if (schedulerService) await schedulerService.stop();
  if (adapterManager) await adapterManager.shutdown();
  if (relayCore) await relayCore.close();
  if (traceStore) traceStore.close();
  if (meshCore) {
    meshCore.stopPeriodicReconciliation();
    meshCore.close();
  }
  await tunnelManager.stop();
}

async function shutdown() {
  logger.info('Shutting down...');
  await shutdownServices();
  process.exit(0);
}
```

## Step 3: Create apps/server/src/routes/admin.ts

```typescript
import { Router } from 'express';
import { spawn } from 'child_process';
import fs from 'fs/promises';
import rateLimit from 'express-rate-limit';

interface AdminDeps {
  dorkHome: string;
  shutdownServices: () => Promise<void>;
  closeDb: () => void;
}

function triggerRestart(): void {
  if (process.env.NODE_ENV === 'development') {
    // Dev mode: nodemon/turbo watches for exit and restarts
    process.exit(0);
  } else {
    // Production/CLI mode: spawn new process, then exit
    const child = spawn(process.argv[0], process.argv.slice(1), {
      detached: true,
      stdio: 'inherit',
      env: process.env,
    });
    child.unref();
    process.exit(0);
  }
}

export function createAdminRouter(deps: AdminDeps): Router {
  const router = Router();

  const adminLimiter = rateLimit({
    windowMs: 5 * 60 * 1000, // 5 minutes
    max: 3,
    message: { error: 'Too many admin requests. Try again later.' },
  });
  router.use(adminLimiter);

  router.post('/reset', (req, res) => {
    const { confirm } = req.body ?? {};
    if (confirm !== 'reset') {
      res.status(400).json({ error: 'Missing or invalid confirm field. Send { confirm: "reset" }.' });
      return;
    }

    res.status(200).json({ message: 'Reset initiated. Server will restart.' });

    setImmediate(async () => {
      try {
        await deps.shutdownServices();
        deps.closeDb();
        await fs.rm(deps.dorkHome, { recursive: true, force: true });
      } catch {
        // Best-effort cleanup; restart regardless
      }
      triggerRestart();
    });
  });

  router.post('/restart', (_req, res) => {
    res.status(200).json({ message: 'Restart initiated.' });

    setImmediate(async () => {
      try {
        await deps.shutdownServices();
      } catch {
        // Best-effort teardown; restart regardless
      }
      triggerRestart();
    });
  });

  return router;
}
```

## Step 4: Mount admin router in index.ts

In the `start()` function of `apps/server/src/index.ts`, after the other route mounts, add:

```typescript
import { createAdminRouter } from './routes/admin.js';

// Inside start(), after other app.use() calls:
app.use('/api/admin', createAdminRouter({
  dorkHome,
  shutdownServices,
  closeDb: () => db.close(),
}));
```

The `dorkHome` variable should already be available in the `start()` function scope (it's the resolved DORK_HOME path). If `db` is not directly accessible, pass a `closeDb` closure from wherever the database connection is managed.

## Step 5: Write server tests

Create `apps/server/src/routes/__tests__/admin.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import express from 'express';
import request from 'supertest';
import { createAdminRouter } from '../admin.js';

// Mock fs/promises
vi.mock('fs/promises', () => ({
  default: { rm: vi.fn().mockResolvedValue(undefined) },
}));

// Mock child_process
vi.mock('child_process', () => ({
  spawn: vi.fn(() => ({ unref: vi.fn() })),
}));

// Mock process.exit
const mockExit = vi.spyOn(process, 'exit').mockImplementation(() => undefined as never);

describe('Admin routes', () => {
  let app: express.Express;
  let mockShutdownServices: ReturnType<typeof vi.fn>;
  let mockCloseDb: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
    mockShutdownServices = vi.fn().mockResolvedValue(undefined);
    mockCloseDb = vi.fn();
    app = express();
    app.use(express.json());
    app.use('/api/admin', createAdminRouter({
      dorkHome: '/tmp/test-dork-home',
      shutdownServices: mockShutdownServices,
      closeDb: mockCloseDb,
    }));
  });

  afterEach(() => {
    mockExit.mockClear();
  });

  describe('POST /api/admin/reset', () => {
    it('returns 400 without confirm field', async () => {
      const res = await request(app).post('/api/admin/reset').send({});
      expect(res.status).toBe(400);
      expect(res.body.error).toContain('confirm');
    });

    it('returns 400 with wrong confirm value', async () => {
      const res = await request(app).post('/api/admin/reset').send({ confirm: 'delete' });
      expect(res.status).toBe(400);
    });

    it('returns 200 with correct confirm value', async () => {
      const res = await request(app).post('/api/admin/reset').send({ confirm: 'reset' });
      expect(res.status).toBe(200);
      expect(res.body.message).toContain('Reset initiated');
    });
  });

  describe('POST /api/admin/restart', () => {
    it('returns 200', async () => {
      const res = await request(app).post('/api/admin/restart');
      expect(res.status).toBe(200);
      expect(res.body.message).toContain('Restart initiated');
    });
  });

  describe('rate limiting', () => {
    it('returns 429 after 3 requests within 5 minutes', async () => {
      await request(app).post('/api/admin/restart');
      await request(app).post('/api/admin/restart');
      await request(app).post('/api/admin/restart');
      const res = await request(app).post('/api/admin/restart');
      expect(res.status).toBe(429);
    });
  });
});
```

## Acceptance Criteria

1. `POST /api/admin/reset` with `{ confirm: 'reset' }` returns 200 and initiates async teardown + directory deletion + restart
2. `POST /api/admin/reset` without correct confirm returns 400
3. `POST /api/admin/restart` returns 200 and initiates async teardown + restart
4. Rate limiter returns 429 after 3 requests in 5 minutes
5. `triggerRestart()` calls `process.exit(0)` in dev mode, `spawn()` + `process.exit(0)` in production
6. The existing `shutdown()` signal handler still works identically (refactor is behavioral no-op)
7. All 6 test scenarios pass

## Overview

Extend the Transport interface with two new methods for admin operations, then implement them in both HttpTransport and DirectTransport.

## Step 1: Update Transport interface in packages/shared/src/transport.ts

Add the following two methods to the `Transport` interface, after the `updateAgentByPath` method (at the end of the interface, before the closing brace):

```typescript
// --- Admin Operations ---

/** Initiate a factory reset: delete all DorkOS data and restart the server. */
resetAllData(confirm: string): Promise<{ message: string }>;
/** Initiate a graceful server restart. */
restartServer(): Promise<{ message: string }>;
```

## Step 2: Implement in HttpTransport

In the HttpTransport class (likely in `apps/client/src/layers/shared/lib/http-transport.ts` or similar), add:

```typescript
async resetAllData(confirm: string): Promise<{ message: string }> {
  const res = await fetch(`${this.baseUrl}/api/admin/reset`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ confirm }),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(text);
  }
  return res.json();
}

async restartServer(): Promise<{ message: string }> {
  const res = await fetch(`${this.baseUrl}/api/admin/restart`, {
    method: 'POST',
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(text);
  }
  return res.json();
}
```

## Step 3: Implement in DirectTransport (Obsidian plugin)

In the DirectTransport class (likely in `apps/obsidian-plugin/src/` or `packages/shared/`), add:

```typescript
async resetAllData(_confirm: string): Promise<{ message: string }> {
  throw new Error('Reset and restart are not supported in Obsidian plugin mode.');
}

async restartServer(): Promise<{ message: string }> {
  throw new Error('Reset and restart are not supported in Obsidian plugin mode.');
}
```

## Step 4: Update mock transport in test-utils

In `packages/test-utils/src/mock-factories.ts`, add to the `createMockTransport()` factory:

```typescript
resetAllData: vi.fn().mockResolvedValue({ message: 'Reset initiated. Server will restart.' }),
restartServer: vi.fn().mockResolvedValue({ message: 'Restart initiated.' }),
```

## Acceptance Criteria

1. Transport interface includes `resetAllData(confirm: string)` and `restartServer()` method signatures
2. HttpTransport calls `POST /api/admin/reset` with JSON body `{ confirm }` and `POST /api/admin/restart`
3. Both HttpTransport methods throw on non-OK responses with the response text as the error message
4. DirectTransport throws descriptive errors for both methods
5. Mock transport factory includes both new methods
6. TypeScript compiles without errors (`pnpm typecheck` passes)

## Overview

Create the `AdvancedTab` component that renders a Danger Zone section with Reset and Restart buttons. This component lives at `apps/client/src/layers/features/settings/ui/AdvancedTab.tsx`.

## Step 1: Create AdvancedTab.tsx

Create `apps/client/src/layers/features/settings/ui/AdvancedTab.tsx`:

