## Overview

Create the ResetDialog component with a type-to-confirm safety pattern. The user must type "reset" to enable the destructive action button. On confirm, it calls the transport, clears localStorage, and triggers the restart overlay.

File: `apps/client/src/layers/features/settings/ui/ResetDialog.tsx`

## Step 1: Create ResetDialog.tsx

```typescript
import { useState } from 'react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  Input,
} from '@/layers/shared/ui';
import { useTransport } from '@/layers/shared/model';
import { toast } from 'sonner';

interface ResetDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onResetComplete: () => void;
}

export function ResetDialog({ open, onOpenChange, onResetComplete }: ResetDialogProps) {
  const [confirmText, setConfirmText] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const transport = useTransport();

  const isConfirmed = confirmText === 'reset';

  async function handleReset() {
    setIsSubmitting(true);
    try {
      await transport.resetAllData('reset');
      localStorage.clear();
      onOpenChange(false);
      onResetComplete();
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to reset data');
    } finally {
      setIsSubmitting(false);
    }
  }

  function handleOpenChange(nextOpen: boolean) {
    if (!nextOpen) {
      setConfirmText('');
      setIsSubmitting(false);
    }
    onOpenChange(nextOpen);
  }

  return (
    <AlertDialog open={open} onOpenChange={handleOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Reset All Data</AlertDialogTitle>
          <AlertDialogDescription asChild>
            <div className="space-y-3">
              <p>This will permanently delete all DorkOS data, including:</p>
              <ul className="list-inside list-disc space-y-1 text-sm">
                <li>All Pulse schedules and run history</li>
                <li>All Relay configuration and messages</li>
                <li>All Mesh agent registry data</li>
                <li>Your config file and preferences</li>
                <li>All server logs</li>
              </ul>
              <p>The server will restart automatically. Your UI preferences will also be cleared.</p>
              <p className="font-semibold">This action cannot be undone.</p>
            </div>
          </AlertDialogDescription>
        </AlertDialogHeader>
        <div className="py-2">
          <Input
            placeholder='Type "reset" to confirm'
            value={confirmText}
            onChange={(e) => setConfirmText(e.target.value)}
            data-testid="reset-confirm-input"
          />
        </div>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction
            disabled={!isConfirmed || isSubmitting}
            onClick={handleReset}
            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
          >
            {isSubmitting ? 'Resetting...' : 'Reset All Data'}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}
```

## Step 2: Create tests

Create `apps/client/src/layers/features/settings/__tests__/ResetDialog.test.tsx`:

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import { ResetDialog } from '../ui/ResetDialog';
import { TransportProvider } from '@/layers/shared/model';
import { createMockTransport } from '@dorkos/test-utils';

describe('ResetDialog', () => {
  let mockTransport: ReturnType<typeof createMockTransport>;
  const defaultProps = {
    open: true,
    onOpenChange: vi.fn(),
    onResetComplete: vi.fn(),
  };

  function Wrapper({ children }: { children: React.ReactNode }) {
    return <TransportProvider transport={mockTransport}>{children}</TransportProvider>;
  }

  beforeEach(() => {
    vi.clearAllMocks();
    mockTransport = createMockTransport();
  });

  it('renders submit button as disabled initially', () => {
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    expect(screen.getByRole('button', { name: /reset all data/i })).toBeDisabled();
  });

  it('keeps submit disabled when wrong text is typed', async () => {
    const user = userEvent.setup();
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    await user.type(screen.getByTestId('reset-confirm-input'), 'delete');
    expect(screen.getByRole('button', { name: /reset all data/i })).toBeDisabled();
  });

  it('enables submit when "reset" is typed', async () => {
    const user = userEvent.setup();
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    await user.type(screen.getByTestId('reset-confirm-input'), 'reset');
    expect(screen.getByRole('button', { name: /reset all data/i })).toBeEnabled();
  });

  it('calls transport.resetAllData on submit', async () => {
    const user = userEvent.setup();
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    await user.type(screen.getByTestId('reset-confirm-input'), 'reset');
    await user.click(screen.getByRole('button', { name: /reset all data/i }));
    expect(mockTransport.resetAllData).toHaveBeenCalledWith('reset');
  });

  it('clears localStorage on success', async () => {
    const clearSpy = vi.spyOn(Storage.prototype, 'clear');
    const user = userEvent.setup();
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    await user.type(screen.getByTestId('reset-confirm-input'), 'reset');
    await user.click(screen.getByRole('button', { name: /reset all data/i }));
    await waitFor(() => {
      expect(clearSpy).toHaveBeenCalled();
    });
    clearSpy.mockRestore();
  });

  it('calls onResetComplete callback on success', async () => {
    const user = userEvent.setup();
    render(<ResetDialog {...defaultProps} />, { wrapper: Wrapper });
    await user.type(screen.getByTestId('reset-confirm-input'), 'reset');
    await user.click(screen.getByRole('button', { name: /reset all data/i }));
    await waitFor(() => {
      expect(defaultProps.onResetComplete).toHaveBeenCalled();
    });
  });
});
```

## Acceptance Criteria

1. AlertDialog displays consequence list (Pulse, Relay, Mesh, config, logs)
2. Input field with placeholder 'Type "reset" to confirm'
3. "Reset All Data" button disabled until input value equals 'reset' exactly
4. On submit: calls `transport.resetAllData('reset')`, then `localStorage.clear()`, then `onResetComplete()` callback
5. On error: shows toast with error message, does not trigger overlay
6. Confirm text resets when dialog is closed
7. All 6 test scenarios pass

## Overview

Create a simple confirmation dialog for the server restart action. This is simpler than ResetDialog since no type-to-confirm is needed.

File: `apps/client/src/layers/features/settings/ui/RestartDialog.tsx`

## Step 1: Create RestartDialog.tsx

```typescript
import { useState } from 'react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/layers/shared/ui';
import { useTransport } from '@/layers/shared/model';
import { toast } from 'sonner';

interface RestartDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onRestartComplete: () => void;
}

export function RestartDialog({ open, onOpenChange, onRestartComplete }: RestartDialogProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const transport = useTransport();

  async function handleRestart() {
    setIsSubmitting(true);
    try {
      await transport.restartServer();
      onOpenChange(false);
      onRestartComplete();
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to restart server');
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Restart Server</AlertDialogTitle>
          <AlertDialogDescription>
            This will restart the DorkOS server. All active sessions will be interrupted.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction
            disabled={isSubmitting}
            onClick={handleRestart}
          >
            {isSubmitting ? 'Restarting...' : 'Restart Server'}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}
```

